create table dirkspzm32.lvs_fahrzeuge (
    sid              varchar2(2 char) not null enable,
    res_id           number(*, 0) not null enable,
    firma_nr         number(2, 0) not null enable,
    typ              varchar2(5 char) not null enable,
    stapler_ls_id    number(*, 0),
    max_kg           number(*, 6),
    max_hoehe        number(*, 3),
    max_lte          number(*, 0),
    fahrzeug_ok      varchar2(1 char) default 'T' not null enable,
    anz_test_lte     number(*, 0) default 0 not null enable,
    max_trans_lte    number(*, 0) default 0 not null enable,
    akt_trans_lte    number(*, 0) default 0 not null enable,
    fahrzeug_ausl_ok varchar2(1 char) default 'T' not null enable,
    transp_richtung  varchar2(1 char) default 'B' not null enable
);

alter table dirkspzm32.lvs_fahrzeuge
    add constraint pk_lvs_fahrzeug primary key ( res_id )
        using index enable;


